156	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount int, now time.Time) (ReconcilePlan, bool) {
157		p := ReconcilePlan{
158			BeadID:        b.ID,
159			CurrentFields: currentLifecycleFields(b),
160		}
161		latest := latestLifecycleEvent(events)
162	
163		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
164			p.Reason = "closed bead has stale no_changes lifecycle metadata"
165			p.ClearFields = noChangesFieldsPresent(b)
166			p.RemoveLabels = noChangesLabelsPresent(b)
167			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
168		}
169	
170		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
171			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
172			p.ClearFields = noChangesFieldsPresent(b)
173			p.RemoveLabels = noChangesLabelsPresent(b)
174			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
175		}
176	
177		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
178			p.Reason = "verified no_changes evidence closes as already_satisfied"
179			p.ClearFields = noChangesFieldsPresent(b)
180			p.RemoveLabels = noChangesLabelsPresent(b)
181			p.CloseSatisfied = true
182			return p, true
183		}
184	
185		if isExpiredRetryAfter(b, now) {
186			p.Reason = "expired retry-after metadata no longer blocks execution"
187			p.ClearFields = []string{ExtraRetryAfter}
188			return p, true
189		}
190	
191		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
192			if b.Extra != nil {
193				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
194					return ReconcilePlan{}, false
195				}
196			}
197			p.Reason = "parent/epic work is owned by child beads"
198			p.SetFields = map[string]any{
199				ExtraExecutionElig:   false,
200				ExtraExecutionReason: "parent/epic container; execute child beads first",
201			}
202			return p, true
203		}
204	
205		return ReconcilePlan{}, false
206	}
