208	func (s *Store) applyReconcilePlan(p ReconcilePlan) error {
209		mutate := func(b *Bead) error {
210			if b.Extra == nil {
211				b.Extra = make(map[string]any)
212			}
213			for _, key := range p.ClearFields {
214				delete(b.Extra, key)
215			}
216			for key, value := range p.SetFields {
217				b.Extra[key] = value
218			}
219			for _, label := range p.RemoveLabels {
220				removeLabel(b, label)
221			}
222			for _, label := range p.AddLabels {
223				addLabel(b, label)
224			}
225			addLabel(b, LabelReconciledNoChangesState)
226			appendInlineEvent(b, BeadEvent{
227				Kind:      "lifecycle_reconciled",
228				Summary:   p.Reason,
229				Actor:     "ddx",
230				Source:    "ddx bead reconcile",
231				CreatedAt: time.Now().UTC(),
232			})
233			return nil
234		}
235		var err error
236		// TD-031 §5: reconcile-close is a meta-close that intentionally bypasses
237		// ClosureGate — the bead has no execution session and no closing_commit_sha
238		// of its own; every transitive dependency is closed, supplying evidence by reference.
239		if p.CloseSatisfied {
240			err = s.UpdateWithLifecycleStatus(p.BeadID, StatusClosed, LifecycleTransitionOptions{
241				ManualClose: true,
242				Reason:      p.Reason,
243				Actor:       "ddx",
244				Source:      "ddx bead reconcile",
245			}, mutate)
246		} else {
247			err = s.Update(p.BeadID, func(b *Bead) {
248				_ = mutate(b)
249			})
250		}
251		if err != nil {
252			return err
253		}
254		if p.CloseSatisfied {
255			return s.externalizeEvents(p.BeadID)
256		}
257		return nil
258	}
