// TestClaimMetadataKeys_SharedByReopenAndUnclaim verifies that both Unclaim and
// Reopen clear every key in ClaimMetadataExtraKeys and that unrelated Extra keys
// are not affected.
func TestClaimMetadataKeys_SharedByReopenAndUnclaim(t *testing.T) {
	s := newTestStore(t)

	b, err := s.Create(BeadInput{Title: "claim-metadata-test"})
	require.NoError(t, err)

	// --- part (a): Claim and populate all ClaimMetadataExtraKeys + heartbeat ---
	require.NoError(t, s.ClaimWithOptions(b.ID, "worker", "sess1", "wt1"))

	// Add an unrelated key that must survive cleanup.
	require.NoError(t, s.Update(b.ID, func(upd *Bead) {
		if upd.Extra == nil {
			upd.Extra = make(map[string]any)
		}
		upd.Extra["claim-test-extra"] = "should-survive"
	}))

	// Confirm ClaimMetadataExtraKeys are present before Unclaim.
	got, err := s.Get(b.ID)
	require.NoError(t, err)
	for _, key := range ClaimMetadataExtraKeys {
		assert.Contains(t, got.Extra, key, "key %q should be present after Claim", key)
	}

	// --- part (b): Unclaim clears all ClaimMetadataExtraKeys ---
	require.NoError(t, s.Unclaim(b.ID))
	got, err = s.Get(b.ID)
	require.NoError(t, err)
	for _, key := range ClaimMetadataExtraKeys {
		assert.NotContains(t, got.Extra, key, "Unclaim should remove %q", key)
	}

	// --- part (d) first check: unrelated key survives Unclaim ---
	assert.Equal(t, "should-survive", got.Extra["claim-test-extra"],
		"claim-test-extra must survive Unclaim")

	// --- part (c): Re-claim, then Reopen clears all ClaimMetadataExtraKeys ---
	require.NoError(t, s.ClaimWithOptions(b.ID, "worker", "sess2", "wt2"))
	require.NoError(t, s.Reopen(b.ID, "", ""))
	got, err = s.Get(b.ID)
	require.NoError(t, err)
	for _, key := range ClaimMetadataExtraKeys {
		assert.NotContains(t, got.Extra, key, "Reopen should remove %q", key)
	}

	// --- part (d) second check: unrelated key survives Reopen ---
	assert.Equal(t, "should-survive", got.Extra["claim-test-extra"],
		"claim-test-extra must survive Reopen")
}
